1	//! A set based on a lock-free skip list. See [`SkipSet`].
2	
3	use core::{
4	    fmt,
5	    ops::{Bound, Deref, RangeBounds},
6	};
7	
8	use crate::{
9	    comparator::{BasicComparator, Comparator},
10	    map,
11	};
12	
13	/// A set based on a lock-free skip list.
14	///
15	/// This is an alternative to [`BTreeSet`] which supports
16	/// concurrent access across multiple threads.
17	///
18	/// A custom comparator may be provided, causing all
19	/// elements to be ordered by the comparison function used
20	/// instead of the standard `Ord` impl. See [`Comparator`].
21	///
22	/// [`BTreeSet`]: std::collections::BTreeSet
23	/// [`Comparator`]: crate::comparator::Comparator
24	pub struct SkipSet<T, C = BasicComparator> {
25	    inner: map::SkipMap<T, (), C>,
26	}
27	
28	impl<T> SkipSet<T> {
29	    /// Returns a new, empty set with the default comparator.
30	    ///
31	    /// # Example
32	    ///
33	    /// ```
34	    /// use crossbeam_skiplist::SkipSet;
35	    ///
36	    /// let set: SkipSet<i32> = SkipSet::new();
37	    /// ```
38	    pub fn new() -> Self {
39	        Self {
40	            inner: map::SkipMap::new(),
41	        }
42	    }
43	}
44	
45	impl<T, C> SkipSet<T, C> {
46	    /// Returns a new, empty set with the given comparator.
47	    ///
48	    /// # Example
49	    ///
50	    /// ```
51	    /// use crossbeam_skiplist::{SkipSet, comparator::BasicComparator};
52	    ///
53	    /// let set: SkipSet<i32> = SkipSet::with_comparator(BasicComparator);
54	    /// ```
55	    pub fn with_comparator(comparator: C) -> Self {
56	        Self {
57	            inner: map::SkipMap::with_comparator(comparator),
58	        }
59	    }
60	
61	    /// Returns `true` if the set is empty.
62	    ///
63	    /// # Example
64	    ///
65	    /// ```
66	    /// use crossbeam_skiplist::SkipSet;
67	    ///
68	    /// let set = SkipSet::new();
69	    /// assert!(set.is_empty());
70	    ///
71	    /// set.insert(1);
72	    /// assert!(!set.is_empty());
73	    /// ```
74	    pub fn is_empty(&self) -> bool {
75	        self.inner.is_empty()
76	    }
77	
78	    /// Returns the number of entries in the set.
79	    ///
80	    /// If the set is being concurrently modified, consider the returned number just an
81	    /// approximation without any guarantees.
82	    ///
83	    /// # Example
84	    ///
85	    /// ```
86	    /// use crossbeam_skiplist::SkipSet;
87	    ///
88	    /// let set = SkipSet::new();
89	    /// assert_eq!(set.len(), 0);
90	    ///
91	    /// set.insert(1);
92	    /// assert_eq!(set.len(), 1);
93	    /// ```
94	    pub fn len(&self) -> usize {
95	        self.inner.len()
96	    }
97	}
98	
99	impl<T, C> SkipSet<T, C>
100	where
101	    C: Comparator<T>,
102	{
103	    /// Returns the entry with the smallest key.
104	    ///
105	    /// # Example
106	    ///
107	    /// ```
108	    /// use crossbeam_skiplist::SkipSet;
109	    ///
110	    /// let set = SkipSet::new();
111	    /// set.insert(1);
112	    /// assert_eq!(*set.front().unwrap(), 1);
113	    /// set.insert(2);
114	    /// assert_eq!(*set.front().unwrap(), 1);
115	    /// ```
116	    pub fn front(&self) -> Option<Entry<'_, T, C>> {
117	        self.inner.front().map(Entry::new)
118	    }
119	
120	    /// Returns the entry with the largest key.
121	    ///
122	    /// # Example
123	    ///
124	    /// ```
125	    /// use crossbeam_skiplist::SkipSet;
126	    ///
127	    /// let set = SkipSet::new();
128	    /// set.insert(1);
129	    /// assert_eq!(*set.back().unwrap(), 1);
130	    /// set.insert(2);
131	    /// assert_eq!(*set.back().unwrap(), 2);
132	    /// ```
133	    pub fn back(&self) -> Option<Entry<'_, T, C>> {
134	        self.inner.back().map(Entry::new)
135	    }
136	
137	    /// Returns `true` if the set contains a value for the specified key.
138	    ///
139	    /// # Example
140	    ///
141	    /// ```
142	    /// use crossbeam_skiplist::SkipSet;
143	    ///
144	    /// let set: SkipSet<_> = (1..=3).collect();
145	    /// assert!(set.contains(&1));
146	    /// assert!(!set.contains(&4));
147	    /// ```
148	    pub fn contains<Q>(&self, key: &Q) -> bool
149	    where
150	        C: Comparator<T, Q>,
151	        Q: ?Sized,
152	    {
153	        self.inner.contains_key(key)
154	    }
155	
156	    /// Returns an entry with the specified `key`.
157	    ///
158	    /// # Example
159	    ///
160	    /// ```
161	    /// use crossbeam_skiplist::SkipSet;
162	    ///
163	    /// let set: SkipSet<_> = (1..=3).collect();
164	    /// assert_eq!(*set.get(&3).unwrap(), 3);
165	    /// assert!(set.get(&4).is_none());
166	    /// ```
167	    pub fn get<Q>(&self, key: &Q) -> Option<Entry<'_, T, C>>
168	    where
169	        C: Comparator<T, Q>,
170	        Q: ?Sized,
171	    {
172	        self.inner.get(key).map(Entry::new)
173	    }
174	
175	    /// Returns an `Entry` pointing to the lowest element whose key is above
176	    /// the given bound. If no such element is found then `None` is
177	    /// returned.
178	    ///
179	    /// # Example
180	    ///
181	    /// ```
182	    /// use crossbeam_skiplist::SkipSet;
183	    /// use std::ops::Bound::*;
184	    ///
185	    /// let set = SkipSet::new();
186	    /// set.insert(6);
187	    /// set.insert(7);
188	    /// set.insert(12);
189	    ///
190	    /// let greater_than_five = set.lower_bound(Excluded(&5)).unwrap();
191	    /// assert_eq!(*greater_than_five, 6);
192	    ///
193	    /// let greater_than_six = set.lower_bound(Excluded(&6)).unwrap();
194	    /// assert_eq!(*greater_than_six, 7);
195	    ///
196	    /// let greater_than_thirteen = set.lower_bound(Excluded(&13));
197	    /// assert!(greater_than_thirteen.is_none());
198	    /// ```
199	    pub fn lower_bound<'a, Q>(&'a self, bound: Bound<&Q>) -> Option<Entry<'a, T, C>>
200	    where
201	        C: Comparator<T, Q>,
202	        Q: ?Sized,
203	    {
204	        self.inner.lower_bound(bound).map(Entry::new)
205	    }
206	
207	    /// Returns an `Entry` pointing to the highest element whose key is below
208	    /// the given bound. If no such element is found then `None` is
209	    /// returned.
210	    ///
211	    /// # Example
212	    ///
213	    /// ```
214	    /// use crossbeam_skiplist::SkipSet;
215	    /// use std::ops::Bound::*;
216	    ///
217	    /// let set = SkipSet::new();
218	    /// set.insert(6);
219	    /// set.insert(7);
220	    /// set.insert(12);
221	    ///
222	    /// let less_than_eight = set.upper_bound(Excluded(&8)).unwrap();
223	    /// assert_eq!(*less_than_eight, 7);
224	    ///
225	    /// let less_than_six = set.upper_bound(Excluded(&6));
226	    /// assert!(less_than_six.is_none());
227	    /// ```
228	    pub fn upper_bound<'a, Q>(&'a self, bound: Bound<&Q>) -> Option<Entry<'a, T, C>>
229	    where
230	        C: Comparator<T, Q>,
231	        Q: ?Sized,
232	    {
233	        self.inner.upper_bound(bound).map(Entry::new)
234	    }
235	
236	    /// Finds an entry with the specified key, or inserts a new `key`-`value` pair if none exist.
237	    ///
238	    /// # Example
239	    ///
240	    /// ```
241	    /// use crossbeam_skiplist::SkipSet;
242	    ///
243	    /// let set = SkipSet::new();
244	    /// let entry = set.get_or_insert(2);
245	    /// assert_eq!(*entry, 2);
246	    /// ```
247	    pub fn get_or_insert(&self, key: T) -> Entry<'_, T, C> {
248	        Entry::new(self.inner.get_or_insert(key, ()))
249	    }
250	
251	    /// Returns an iterator over all entries in the set.
252	    ///
253	    /// # Examples
254	    ///
255	    /// ```
256	    /// use crossbeam_skiplist::SkipSet;
257	    ///
258	    /// let set = SkipSet::new();
259	    /// set.insert(6);
260	    /// set.insert(7);
261	    /// set.insert(12);
262	    ///
263	    /// let mut set_iter = set.iter();
264	    /// assert_eq!(*set_iter.next().unwrap(), 6);
265	    /// assert_eq!(*set_iter.next().unwrap(), 7);
266	    /// assert_eq!(*set_iter.next().unwrap(), 12);
267	    /// assert!(set_iter.next().is_none());
268	    /// ```
269	    pub fn iter(&self) -> Iter<'_, T, C> {
270	        Iter {
271	            inner: self.inner.iter(),
272	        }
273	    }
274	
275	    /// Returns an iterator over a subset of entries in the set.
276	    ///
277	    /// # Example
278	    ///
279	    /// ```
280	    /// use crossbeam_skiplist::SkipSet;
281	    ///
282	    /// let set = SkipSet::new();
283	    /// set.insert(6);
284	    /// set.insert(7);
285	    /// set.insert(12);
286	    ///
287	    /// let mut set_range = set.range(5..=8);
288	    /// assert_eq!(*set_range.next().unwrap(), 6);
289	    /// assert_eq!(*set_range.next().unwrap(), 7);
290	    /// assert!(set_range.next().is_none());
291	    /// ```
292	    pub fn range<Q, R>(&self, range: R) -> Range<'_, Q, R, T, C>
293	    where
294	        R: RangeBounds<Q>,
295	        C: Comparator<T, Q>,
296	        Q: ?Sized,
297	    {
298	        Range {
299	            inner: self.inner.range(range),
300	        }
301	    }
302	}
