304	impl<T, C> SkipSet<T, C>
305	where
306	    C: Comparator<T>,
307	    T: Send + 'static,
308	{
309	    /// Inserts a `key`-`value` pair into the set and returns the new entry.
310	    ///
311	    /// If there is an existing entry with this key, it will be removed before inserting the new
312	    /// one.
313	    ///
314	    /// # Example
315	    ///
316	    /// ```
317	    /// use crossbeam_skiplist::SkipSet;
318	    ///
319	    /// let set = SkipSet::new();
320	    /// set.insert(2);
321	    /// assert_eq!(*set.get(&2).unwrap(), 2);
322	    /// ```
323	    pub fn insert(&self, key: T) -> Entry<'_, T, C> {
324	        Entry::new(self.inner.insert(key, ()))
325	    }
326	
327	    /// Removes an entry with the specified key from the set and returns it.
328	    ///
329	    /// The value will not actually be dropped until all references to it have gone
330	    /// out of scope.
331	    ///
332	    /// # Example
333	    ///
334	    /// ```
335	    /// use crossbeam_skiplist::SkipSet;
336	    ///
337	    /// let set = SkipSet::new();
338	    /// set.insert(2);
339	    /// assert_eq!(*set.remove(&2).unwrap(), 2);
340	    /// assert!(set.remove(&2).is_none());
341	    /// ```
342	    pub fn remove<Q>(&self, key: &Q) -> Option<Entry<'_, T, C>>
343	    where
344	        C: Comparator<T, Q>,
345	        Q: ?Sized,
346	    {
347	        self.inner.remove(key).map(Entry::new)
348	    }
349	
350	    /// Removes an entry from the front of the set.
351	    /// Returns the removed entry.
352	    ///
353	    /// The value will not actually be dropped until all references to it have gone
354	    /// out of scope.
355	    ///
356	    /// # Example
357	    ///
358	    /// ```
359	    /// use crossbeam_skiplist::SkipSet;
360	    ///
361	    /// let set = SkipSet::new();
362	    /// set.insert(1);
363	    /// set.insert(2);
364	    ///
365	    /// assert_eq!(*set.pop_front().unwrap(), 1);
366	    /// assert_eq!(*set.pop_front().unwrap(), 2);
367	    ///
368	    /// // All entries have been removed now.
369	    /// assert!(set.is_empty());
370	    /// ```
371	    pub fn pop_front(&self) -> Option<Entry<'_, T, C>> {
372	        self.inner.pop_front().map(Entry::new)
373	    }
374	
375	    /// Removes an entry from the back of the set.
376	    /// Returns the removed entry.
377	    ///
378	    /// The value will not actually be dropped until all references to it have gone
379	    /// out of scope.
380	    ///
381	    /// # Example
382	    ///
383	    /// ```
384	    /// use crossbeam_skiplist::SkipSet;
385	    ///
386	    /// let set = SkipSet::new();
387	    /// set.insert(1);
388	    /// set.insert(2);
389	    ///
390	    /// assert_eq!(*set.pop_back().unwrap(), 2);
391	    /// assert_eq!(*set.pop_back().unwrap(), 1);
392	    ///
393	    /// // All entries have been removed now.
394	    /// assert!(set.is_empty());
395	    /// ```
396	    pub fn pop_back(&self) -> Option<Entry<'_, T, C>> {
397	        self.inner.pop_back().map(Entry::new)
398	    }
399	
400	    /// Iterates over the set and removes every entry.
401	    ///
402	    /// # Example
403	    ///
404	    /// ```
405	    /// use crossbeam_skiplist::SkipSet;
406	    ///
407	    /// let set = SkipSet::new();
408	    /// set.insert(1);
409	    /// set.insert(2);
410	    ///
411	    /// set.clear();
412	    /// assert!(set.is_empty());
413	    /// ```
414	    pub fn clear(&self) {
415	        self.inner.clear();
416	    }
417	}
