484	        Self { inner }
485	    }
486	
487	    /// Returns a reference to the value.
488	    pub fn value(&self) -> &T {
489	        self.inner.key()
490	    }
491	
492	    /// Returns `true` if the entry is removed from the set.
493	    pub fn is_removed(&self) -> bool {
